import { useState } from "react";
import { useNavigate } from "react-router-dom";
import { useCart } from "../context/CartContext";
import { useAuth } from "../context/AuthContext";
import api from "../utils/api";
import { toast } from "react-toastify";
import "./Checkout.css";

export default function Checkout() {
  const { cart, cartTotal, clearCart } = useCart();
  const { user } = useAuth();
  const navigate = useNavigate();
  const [step, setStep] = useState(1);
  const [loading, setLoading] = useState(false);
  const [address, setAddress] = useState({
    street: "", city: "", state: "", zip: "", country: "US",
  });
  const [cardInfo, setCardInfo] = useState({
    number: "", expiry: "", cvc: "", name: "",
  });

  const shipping = cartTotal > 100 ? 0 : 9.99;
  const tax = cartTotal * 0.1;
  const total = cartTotal + shipping + tax;

  const setAddr = (f) => (e) => setAddress({ ...address, [f]: e.target.value });
  const setCard = (f) => (e) => setCardInfo({ ...cardInfo, [f]: e.target.value });

  const handlePlaceOrder = async () => {
    setLoading(true);
    try {
      // Create payment intent
      const { data: { clientSecret } } = await api.post("/api/payment/create-intent", { amount: total });

      // In production, use Stripe.js to confirm the payment with clientSecret
      // For demo, we simulate a successful payment
      const paymentResult = {
        id: `pi_demo_${Date.now()}`,
        status: "succeeded",
        email: user.email,
      };

      // Create order
      const { data } = await api.post("/api/orders", {
        items: cart,
        shippingAddress: address,
        paymentMethod: "stripe",
        paymentResult,
      });

      // Mark as paid
      await api.put(`/api/orders/${data.order._id}/pay`, paymentResult);

      clearCart();
      toast.success("Order placed successfully! 🎉");
      navigate(`/orders`);
    } catch (err) {
      toast.error(err.response?.data?.message || "Payment failed");
    } finally {
      setLoading(false);
    }
  };

  if (cart.length === 0) {
    navigate("/cart");
    return null;
  }

  return (
    <div className="checkout-page">
      <div className="container">
        <div className="page-header">
          <h1>Checkout</h1>
        </div>

        <div className="checkout-layout">
          <div className="checkout-steps">
            {/* Step indicator */}
            <div className="step-indicator">
              {["Shipping", "Payment", "Review"].map((s, i) => (
                <div key={s} className={`step ${step > i + 1 ? "done" : ""} ${step === i + 1 ? "active" : ""}`}>
                  <div className="step-num">{step > i + 1 ? "✓" : i + 1}</div>
                  <span>{s}</span>
                </div>
              ))}
            </div>

            {/* Step 1 — Shipping */}
            {step === 1 && (
              <div className="checkout-form card">
                <h3>Shipping Address</h3>
                <div className="form-group">
                  <label>Street Address</label>
                  <input value={address.street} onChange={setAddr("street")} placeholder="123 Main St" required />
                </div>
                <div className="form-row">
                  <div className="form-group">
                    <label>City</label>
                    <input value={address.city} onChange={setAddr("city")} placeholder="New York" required />
                  </div>
                  <div className="form-group">
                    <label>State</label>
                    <input value={address.state} onChange={setAddr("state")} placeholder="NY" required />
                  </div>
                </div>
                <div className="form-row">
                  <div className="form-group">
                    <label>ZIP Code</label>
                    <input value={address.zip} onChange={setAddr("zip")} placeholder="10001" required />
                  </div>
                  <div className="form-group">
                    <label>Country</label>
                    <select value={address.country} onChange={setAddr("country")}>
                      <option value="US">United States</option>
                      <option value="IN">India</option>
                      <option value="GB">United Kingdom</option>
                      <option value="CA">Canada</option>
                      <option value="AU">Australia</option>
                    </select>
                  </div>
                </div>
                <button
                  className="btn btn-primary"
                  onClick={() => {
                    if (!address.street || !address.city || !address.state || !address.zip)
                      return toast.error("Please fill all address fields");
                    setStep(2);
                  }}
                >
                  Continue to Payment
                </button>
              </div>
            )}

            {/* Step 2 — Payment */}
            {step === 2 && (
              <div className="checkout-form card">
                <h3>Payment Details</h3>
                <p className="stripe-note">🔒 Payments secured by Stripe</p>
                <div className="form-group">
                  <label>Name on Card</label>
                  <input value={cardInfo.name} onChange={setCard("name")} placeholder="John Doe" />
                </div>
                <div className="form-group">
                  <label>Card Number</label>
                  <input
                    value={cardInfo.number}
                    onChange={setCard("number")}
                    placeholder="4242 4242 4242 4242"
                    maxLength={19}
                  />
                </div>
                <div className="form-row">
                  <div className="form-group">
                    <label>Expiry</label>
                    <input value={cardInfo.expiry} onChange={setCard("expiry")} placeholder="MM/YY" maxLength={5} />
                  </div>
                  <div className="form-group">
                    <label>CVC</label>
                    <input value={cardInfo.cvc} onChange={setCard("cvc")} placeholder="123" maxLength={3} />
                  </div>
                </div>
                <div className="form-actions">
                  <button className="btn btn-outline" onClick={() => setStep(1)}>← Back</button>
                  <button
                    className="btn btn-primary"
                    onClick={() => {
                      if (!cardInfo.name || !cardInfo.number || !cardInfo.expiry || !cardInfo.cvc)
                        return toast.error("Please fill all card details");
                      setStep(3);
                    }}
                  >
                    Review Order
                  </button>
                </div>
              </div>
            )}

            {/* Step 3 — Review */}
            {step === 3 && (
              <div className="checkout-form card">
                <h3>Review Your Order</h3>
                <div className="review-items">
                  {cart.map((item, i) => (
                    <div key={i} className="review-item">
                      <img src={item.image || `https://placehold.co/60x75/1a1a1a/f5f5f0?text=${encodeURIComponent(item.name)}`} alt={item.name} />
                      <div>
                        <p className="review-item-name">{item.name}</p>
                        <p className="review-item-meta">{item.size} · {item.color} · Qty {item.quantity}</p>
                      </div>
                      <span>${(item.price * item.quantity).toFixed(2)}</span>
                    </div>
                  ))}
                </div>
                <div className="review-address">
                  <p className="review-label">Shipping to</p>
                  <p>{address.street}, {address.city}, {address.state} {address.zip}, {address.country}</p>
                </div>
                <div className="form-actions">
                  <button className="btn btn-outline" onClick={() => setStep(2)}>← Back</button>
                  <button className="btn btn-primary" onClick={handlePlaceOrder} disabled={loading}>
                    {loading ? "Placing Order..." : `Place Order · $${total.toFixed(2)}`}
                  </button>
                </div>
              </div>
            )}
          </div>

          {/* Summary sidebar */}
          <div className="checkout-summary card">
            <h3>Order Summary</h3>
            <div className="summary-items">
              {cart.map((item, i) => (
                <div key={i} className="summary-item">
                  <span>{item.name} × {item.quantity}</span>
                  <span>${(item.price * item.quantity).toFixed(2)}</span>
                </div>
              ))}
            </div>
            <hr className="divider" />
            <div className="summary-row"><span>Subtotal</span><span>${cartTotal.toFixed(2)}</span></div>
            <div className="summary-row">
              <span>Shipping</span>
              <span>{shipping === 0 ? "Free" : `$${shipping.toFixed(2)}`}</span>
            </div>
            <div className="summary-row"><span>Tax</span><span>${tax.toFixed(2)}</span></div>
            <hr className="divider" />
            <div className="summary-row summary-total">
              <span>Total</span><span>${total.toFixed(2)}</span>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}
